import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import Login from './pages/Login';
import ResetPassword from './pages/ResetPassword';
import Dashboard from './pages/Dashboard';
import DepartmentMaster from './pages/DepartmentMaster';
import ProgrammeMaster from './pages/ProgrammeMaster';
import BlockMaster from './pages/BlockMaster';
import RoomMaster from './pages/RoomMaster';
import RoleMaster from './pages/RoleMaster';
import UserMaster from './pages/UserMaster';
import RaiseComplaint from './pages/RaiseComplaint';
import ComplaintsList from './pages/ComplaintsList';
import ReportScreen from './pages/ReportScreen';
import ProtectedRoute from './components/ProtectedRoute';

function App() {
  return (
    <Router>
      <Routes>
        <Route path="/" element={<Login />} />
        <Route path="/reset-password/:token" element={<ResetPassword />} />
        <Route path="/dashboard" element={<ProtectedRoute><Dashboard /></ProtectedRoute>} />

        {/* Master Screens (Admin-only actions are enforced server-side) */}
        <Route path="/department" element={<ProtectedRoute><DepartmentMaster /></ProtectedRoute>} />
        <Route path="/programme" element={<ProtectedRoute><ProgrammeMaster /></ProtectedRoute>} />
        <Route path="/block" element={<ProtectedRoute><BlockMaster /></ProtectedRoute>} />
        <Route path="/room" element={<ProtectedRoute><RoomMaster /></ProtectedRoute>} />
        <Route path="/role" element={<ProtectedRoute><RoleMaster /></ProtectedRoute>} />
        <Route path="/users" element={<ProtectedRoute><UserMaster /></ProtectedRoute>} />

        {/* Transactions & Reports */}
        <Route path="/raise-complaint" element={<ProtectedRoute><RaiseComplaint /></ProtectedRoute>} />
        <Route path="/complaints" element={<ProtectedRoute><ComplaintsList /></ProtectedRoute>} />
        <Route path="/report" element={<ProtectedRoute><ReportScreen /></ProtectedRoute>} />
      </Routes>
    </Router>
  );
}

export default App;
